/**
 * OKKI 全量数据抓取 — CDP 连接 + 自动翻页
 *
 * 使用前：
 * 1. Chrome 已通过 --remote-debugging-port=9222 启动
 * 2. 已在 Chrome 中登录 OKKI
 * 3. node scripts/scrape_cdp_full.js
 *
 * 自动翻页抓取全量客户列表，无需手动操作。
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const CDP_URL = 'http://localhost:9222';
const OUTPUT_DIR = path.join(__dirname, '..', 'data');
const PAGE_SIZE = 50; // 每页多拉点
const REQUEST_DELAY = 800; // 请求间隔，不压服务器

if (!fs.existsSync(OUTPUT_DIR)) {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
}

async function main() {
  console.log('[Full Scraper] 连接到 Chrome ...');
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  let page = ctx.pages().find(p => p.url().includes('xiaoman'));

  if (!page) {
    page = await ctx.newPage();
    await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 30000 });
  }

  const currentUrl = page.url();
  console.log(`[Full Scraper] 当前页面: ${currentUrl}`);

  if (currentUrl.includes('login')) {
    console.error('[Full Scraper] 尚未登录，请先在 Chrome 中登录 OKKI 再运行此脚本。');
    process.exit(1);
  }

  // 从页面中提取认证信息
  const cookies = await ctx.cookies();
  const cookieHeader = cookies.map(c => `${c.name}=${c.value}`).join('; ');

  // 获取第一页，了解总数
  console.log('[Full Scraper] 获取客户总数 ...');
  const firstPage = await page.evaluate(async ({ cookieHeader, pageSize }) => {
    const res = await fetch('https://crm.xiaoman.cn/api/customerV3Read/companyList', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Cookie': cookieHeader,
      },
      credentials: 'include',
      body: JSON.stringify({
        page: 1,
        pageSize: pageSize,
        sort: 'create_time',
        order: 'desc',
      }),
    });
    return res.json();
  }, { cookieHeader, pageSize: PAGE_SIZE });

  const total = firstPage.data?.total || firstPage.total || 0;
  const totalPages = Math.ceil(total / PAGE_SIZE);
  console.log(`[Full Scraper] 总数: ${total}, 每页: ${PAGE_SIZE}, 共 ${totalPages} 页`);

  if (total === 0) {
    console.error('[Full Scraper] 客户总数为 0，请检查登录状态');
    process.exit(1);
  }

  const allCustomers = [];
  const allApiResponses = [];

  // 保存第一页
  allApiResponses.push({ page: 1, url: '/api/customerV3Read/companyList', data: firstPage });
  if (firstPage.data?.list) allCustomers.push(...firstPage.data.list);
  else if (firstPage.list) allCustomers.push(...firstPage.list);
  console.log(`[Full Scraper] 第 1/${totalPages} 页 → 累计 ${allCustomers.length} 人`);

  // 逐页抓取
  for (let p = 2; p <= totalPages; p++) {
    await new Promise(r => setTimeout(r, REQUEST_DELAY));

    const result = await page.evaluate(async ({ pageNum, pageSize, cookieHeader }) => {
      const res = await fetch('https://crm.xiaoman.cn/api/customerV3Read/companyList', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Cookie': cookieHeader,
        },
        credentials: 'include',
        body: JSON.stringify({
          page: pageNum,
          pageSize: pageSize,
          sort: 'create_time',
          order: 'desc',
        }),
      });
      return res.json();
    }, { pageNum: p, pageSize: PAGE_SIZE, cookieHeader });

    allApiResponses.push({ page: p, url: '/api/customerV3Read/companyList', data: result });

    const list = result.data?.list || result.list || [];
    allCustomers.push(...list);
    console.log(`[Full Scraper] 第 ${p}/${totalPages} 页 → 累计 ${allCustomers.length} 人`);

    // 每 5 页保存一次中间结果
    if (p % 5 === 0) {
      saveSnapshot(allCustomers, allApiResponses, total);
    }
  }

  // 最终保存
  const ts = saveSnapshot(allCustomers, allApiResponses, total);
  console.log(`\n[Full Scraper] ✅ 全量 ${allCustomers.length} 人已保存 → ${ts}`);
}

function saveSnapshot(customers, apiResponses, total) {
  const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const fp = path.join(OUTPUT_DIR, `okki_full_${ts}.json`);

  fs.writeFileSync(fp, JSON.stringify({
    capturedAt: ts,
    totalExpected: total,
    totalCaptured: customers.length,
    pageCount: apiResponses.length,
    customers: customers.map(c => ({
      id: c.serial_id_info?.info_value || c.id || '',
      name: c.name_info?.info_value || c.name || '',
      level: c.cus_tag_info?.[0]?.info_label || '',
      status: c.trail_status_info?.info_label || '',
      source: c.origin_list_info?.map(o => o.info_label) || [],
      creator: c.create_user_info?.info_label || '',
      lastEditor: c.last_edit_user_info?.info_label || '',
      serialNumber: c.serial_id_info?.info_value || '',
      score: c.score_info?.info_value?.data || 0,
      orderCount: c.performance_order_count_info?.info_value || 0,
      raw: c,
    })),
  }, null, 2));

  console.log(`  [Save] ${fp}`);
  return ts;
}

main().catch(err => {
  console.error('[Full Scraper] 错误:', err.message);
  process.exit(1);
});

