 * OKKI 全量数据抓取 — CDP 连接 + 自动翻页（翻到空页为止）
 *
 * 使用前：
 * 1. Chrome 已通过 --remote-debugging-port=9222 启动并登录 OKKI
 * 2. node scripts/scrape_cdp_full.js
 */

const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const CDP_URL = 'http://localhost:9222';
const OUTPUT_DIR = path.join(__dirname, '..', 'data');
const PAGE_SIZE = 100;
const REQUEST_DELAY = 600;

if (!fs.existsSync(OUTPUT_DIR)) {
  fs.mkdirSync(OUTPUT_DIR, { recursive: true });
}

function apiCall(pageNum) {
  return `(async (pageSize, page) => {
    return new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest();
      xhr.open('POST', 'https://crm.xiaoman.cn/api/customerV3Read/companyList', true);
      xhr.setRequestHeader('Content-Type', 'application/json');
      xhr.withCredentials = true;
      xhr.onload = () => resolve(JSON.parse(xhr.responseText));
      xhr.onerror = () => reject(new Error('XHR failed'));
      xhr.send(JSON.stringify({ page, pageSize, sort: 'create_time', order: 'desc' }));
    });
  })(${PAGE_SIZE}, ${pageNum})`;
}

async function main() {
  console.log('[Full Scraper] 连接到 Chrome ...');
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  let page = ctx.pages().find(p => p.url().includes('xiaoman'));

  if (!page) {
    page = await ctx.newPage();
    await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 30000 });
  }

  console.log(`[Full Scraper] 页面: ${page.url()}`);
  if (page.url().includes('login')) {
    console.error('[Full Scraper] 未登录，请先在 Chrome 中登录 OKKI');
    process.exit(1);
  }

  const allCustomers = [];
  let pageNum = 1;

  while (true) {
    const result = await page.evaluate(apiCall(pageNum));
    const list = result.data?.list || [];

    if (list.length === 0) {
      console.log(`[Full Scraper] 第 ${pageNum} 页为空，抓取完成`);
      break;
    }

    allCustomers.push(...list);
    console.log(`[Full Scraper] 第 ${pageNum} 页 → ${list.length} 人 (累计 ${allCustomers.length})`);

    // 每 5 页保存快照
    if (pageNum % 5 === 0) {
      saveSnapshot(allCustomers, pageNum);
    }

    pageNum++;
    await new Promise(r => setTimeout(r, REQUEST_DELAY));
  }

  // 最终保存
  const ts = saveSnapshot(allCustomers, pageNum - 1);
  console.log(`\n[Full Scraper] ✅ 全量 ${allCustomers.length} 人 → ${ts}`);
  process.exit(0);
}

function saveSnapshot(customers, pages) {
  const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
  const fp = path.join(OUTPUT_DIR, `okki_full_${ts}.json`);
  fs.writeFileSync(fp, JSON.stringify({
    capturedAt: ts,
    totalCaptured: customers.length,
    pages,
    customers,
  }, null, 2));
  console.log(`  [Save] ${fp}`);
  return ts;
}

main().catch(err => {
  console.error('[Full Scraper] 错误:', err.message);
  process.exit(1);
});
