const data = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json');
const customers = data.customers;

// ===== 2. 关键字段的值分布和合理性 =====
function stats(key, extractor) {
  const vals = customers.map(c => extractor(c)).filter(v => v !== null && v !== undefined && v !== '' && !(Array.isArray(v) && v.length === 0));
  const unique = new Set(vals.map(v => typeof v === 'object' ? JSON.stringify(v) : v));
  return { total: customers.length, nonEmpty: vals.length, pct: ((vals.length/customers.length)*100).toFixed(1), unique: unique.size };
}

console.log('===== 关键字段值分布 =====');
console.log('');

// 客户名称
const names = customers.map(c => c.name_info?.info_value || c.name || '');
console.log('客户名称: ' + names.filter(n=>n).length + ' 有值, 空: ' + names.filter(n=>!n).length + ', 例: ' + names.slice(0,5).join(', '));

// 客户等级
const levels = customers.map(c => c.cus_tag_info?.[0]?.info_label || '无标签');
const levelDist = {};
levels.forEach(l => levelDist[l] = (levelDist[l]||0)+1);
console.log('客户等级分布:');
Object.entries(levelDist).sort((a,b)=>b[1]-a[1]).forEach(([k,v]) => console.log('  ' + k + ': ' + v + ' (' + ((v/customers.length)*100).toFixed(1) + '%)'));

// 状态
const statuses = customers.map(c => c.trail_status_info?.info_label || '无');
const statusDist = {};
statuses.forEach(s => statusDist[s] = (statusDist[s]||0)+1);
console.log('跟进状态分布:');
Object.entries(statusDist).sort((a,b)=>b[1]-a[1]).forEach(([k,v]) => console.log('  ' + k + ': ' + v + ' (' + ((v/customers.length)*100).toFixed(1) + '%)'));

// 国家
const countries = customers.map(c => c.country_region?.country_name_cn || c.country || '未知');
const countryDist = {};
countries.forEach(c => countryDist[c] = (countryDist[c]||0)+1);
console.log('国家分布 (top 15):');
Object.entries(countryDist).sort((a,b)=>b[1]-a[1]).slice(0,15).forEach(([k,v]) => console.log('  ' + k + ': ' + v));

// 订单数
const orders = customers.map(c => c.performance_order_count || 0);
console.log('订单数: 有订单=' + orders.filter(o=>o>0).length + ', 0单=' + orders.filter(o=>o===0).length + ', max=' + Math.max(...orders) + ', avg=' + (orders.reduce((a,b)=>a+b,0)/orders.length).toFixed(2));

