const data = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json');
const customers = data.customers;

// ===== 5. Score分析 + 数据异常检查 =====
console.log('===== 客户Score分布 =====');
const scores = customers.map(c => c.score?.data || 0);
const sortedScores = [...scores].sort((a,b)=>a-b);
console.log('Score范围: ' + sortedScores[0] + ' ~ ' + sortedScores[sortedScores.length-1]);
console.log('Score中位数: ' + sortedScores[Math.floor(sortedScores.length/2)]);
console.log('Score分布:');
const buckets = {0:0, '1-10':0, '11-20':0, '21-30':0, '31-40':0, '41-50':0, '51+':0};
scores.forEach(s => {
  if (s===0) buckets[0]++;
  else if (s<=10) buckets['1-10']++;
  else if (s<=20) buckets['11-20']++;
  else if (s<=30) buckets['21-30']++;
  else if (s<=40) buckets['31-40']++;
  else if (s<=50) buckets['41-50']++;
  else buckets['51+']++;
});
for (const [k,v] of Object.entries(buckets)) console.log('  ' + k + ': ' + v + ' (' + ((v/customers.length)*100).toFixed(1) + '%)');

// Score与等级的关系
console.log('');
console.log('===== Score vs 等级 =====');
const levelScoreMap = {};
for (const c of customers) {
  const level = c.cus_tag_info?.[0]?.info_label || '无';
  const score = c.score?.data || 0;
  if (!levelScoreMap[level]) levelScoreMap[level] = {scores:[], count:0};
  levelScoreMap[level].scores.push(score);
  levelScoreMap[level].count++;
}
for (const [level, info] of Object.entries(levelScoreMap)) {
  const avg = (info.scores.reduce((a,b)=>a+b,0) / info.scores.length).toFixed(1);
  console.log('  ' + level + ': avg score=' + avg + ', n=' + info.count);
}

// ===== 6. 数据异常检测 =====
console.log('');
