const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 确保在列表页
  if (!page.url().includes('/list')) {
    await page.goto('https://crm.xiaoman.cn/crm/customer/list', { waitUntil: 'domcontentloaded', timeout: 30000 });
    await page.waitForTimeout(3000);
  }

  // 拦截所有 API 响应
  const apiCalls = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (!url.includes('xiaoman.cn/api') && !url.includes('xiaoman.cn/siteapi')) return;
    const ct = resp.headers()['content-type'] || '';
    if (!ct.includes('json')) return;
    try {
      const body = await resp.json();
      apiCalls.push({ url: url.split('?')[0], status: resp.status(), keys: Object.keys(body), hasData: !!body.data });
    } catch(e) {}
  });

  // 点击第一个客户行 — 尝试多种选择器
  console.log('Trying to click first customer row...');
  const clickSelectors = [
    'tbody tr:first-child',
    'table tr:first-child td:first-child a',
    'table tr:first-child td:nth-child(2)',
    '[class*=table] [class*=row]:first-child',
    '[class*=list] [class*=item]:first-child',
    '.customer-list tr:first-child',
    '[class*=customer] [class*=row]:first-child',
  ];

  let clicked = false;
  for (const sel of clickSelectors) {
    try {
      const el = page.locator(sel).first();
      if (await el.isVisible({ timeout: 500 }).catch(() => false)) {
        console.log('Found clickable element:', sel);
        await el.click();
        clicked = true;
        await page.waitForTimeout(4000);
        break;
      }
    } catch(e) {}
  }

  if (!clicked) {
    console.log('Could not find clickable row, trying text-based click...');
    // 尝试点击包含客户名称的元素
    const customers = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json').customers;
    const targetName = customers[0].name;
    console.log('Looking for text:', targetName);
    try {
      await page.locator('text=' + targetName).first().click({ timeout: 5000 });
      clicked = true;
      await page.waitForTimeout(4000);
    } catch(e) {
      console.log('Text click failed:', e.message);
    }
  }

  console.log('Current URL after click:', page.url());
  console.log('');
  console.log('===== APIs called (' + apiCalls.length + ' total) =====');
  apiCalls.forEach(a => {
    const label = a.url.includes('chat') || a.url.includes('message') || a.url.includes('im') ? '💬' :
                  a.url.includes('mail') || a.url.includes('email') ? '📧' :
                  a.url.includes('trail') || a.url.includes('follow') ? '📝' :
                  a.url.includes('file') || a.url.includes('attach') ? '📎' :
                  a.url.includes('customer') || a.url.includes('company') ? '👤' : '  ';
    console.log(label + ' ' + a.status + ' ' + a.url + ' | keys=' + a.keys.join(','));
  });

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
