node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 拦截所有 API
  const apiCalls = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (!url.includes('xiaoman.cn/api')) return;
    const ct = resp.headers()['content-type'] || '';
    if (!ct.includes('json')) return;
    try {
      const body = await resp.json();
      apiCalls.push({
        url: url.split('?')[0],
        status: resp.status(),
        dataKeys: body.data ? Object.keys(body.data).slice(0, 15) : [],
        listLen: body.data?.list?.length,
        msgsLen: body.data?.messages?.length,
        recordsLen: body.data?.records?.length,
        total: body.data?.total || body.data?.totalItem,
      });
    } catch(e) {}
  });

  // 先点击第一个数据行的客户名称链接
  console.log('Clicking first data row...');

  // 找到数据行（不是标题行）
  const clicked = await page.evaluate(() => {
    const rows = document.querySelectorAll('.row-item:not(.row-item__title)');
    if (rows.length > 0) {
      rows[0].click();
      return true;
    }
    return false;
  });
  console.log('Row clicked:', clicked);
  await page.waitForTimeout(4000);

  console.log('');
  console.log('APIs after clicking row (' + apiCalls.length + '):');
  apiCalls.forEach(a => {
    const flags = [];
    if (a.listLen !== undefined) flags.push('list=' + a.listLen);
    if (a.msgsLen !== undefined) flags.push('msgs=' + a.msgsLen);
    if (a.recordsLen !== undefined) flags.push('records=' + a.recordsLen);
    if (a.total !== undefined) flags.push('total=' + a.total);
    const label = a.url.includes('chat') || a.url.includes('message') ? 'CHAT' :
                  a.url.includes('mail') ? 'MAIL' :
                  a.url.includes('trail') ? 'TRAIL' : '';
    console.log('  [' + label + '] ' + a.status + ' ' + a.url + ' | ' + flags.join(', ') + ' | keys=' + a.dataKeys.join(','));
  });

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
" 2>&1

