const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 看 detail 页面结构
  const tabs = await page.evaluate(() => {
    const result = [];
    // 找所有可能的 tab
    document.querySelectorAll('[class*=tab], [class*=Tab], [role=tab]').forEach(el => {
      result.push({ text: el.textContent.trim(), class: el.className, role: el.getAttribute('role') });
    });
    // 也找侧边栏/面板
    document.querySelectorAll('[class*=drawer], [class*=panel], [class*=sidebar], [class*=detail]').forEach(el => {
      const txt = el.textContent.trim().substring(0, 200);
      if (txt.length > 10) result.push({ type: 'panel', class: el.className, preview: txt });
    });
    return result.slice(0, 30);
  });
  console.log('Tabs found:');
  tabs.forEach(t => console.log('  ', JSON.stringify(t)));

  // 看页面上的按钮文字
  const btns = await page.evaluate(() => {
    const texts = new Set();
    document.querySelectorAll('button, [class*=action], [class*=operate], a').forEach(el => {
      const t = el.textContent.trim();
      if (t && t.length < 20) texts.add(t);
    });
    return [...texts].slice(0, 50);
  });
  console.log('');
  console.log('All button/action texts:', btns.join(', '));

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
