const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 获取所有 frames
  const allFrames = page.frames();
  console.log('Total frames:', allFrames.length);
  allFrames.forEach((f, i) => {
    console.log('Frame ' + i + ': ' + f.url().substring(0, 120) + ' | name=' + f.name());
  });

  // 找 TM iframe
  const tmFrame = allFrames.find(f => f.url().includes('onetalk.alibaba.com'));

  if (tmFrame) {
    console.log('');
    console.log('=== TM iframe 可访问! ===');
    console.log('URL:', tmFrame.url().substring(0, 200));

    // 尝试在 iframe 中执行
    try {
      const frameContent = await tmFrame.evaluate(() => {
        return {
          title: document.title,
          bodyText: document.body?.innerText?.substring(0, 500),
          hasReact: !!document.querySelector('[data-reactroot]'),
          divCount: document.querySelectorAll('div').length,
        };
      });
      console.log('Frame content:', JSON.stringify(frameContent, null, 2));
    } catch(e) {
      console.log('Frame eval error:', e.message);
    }
  } else {
    console.log('TM iframe not found in frames list');

    // 尝试通过 CDP 直接访问 iframe
    console.log('Trying CDP approach...');
    const cdpSession = await page.context().newCDPSession(page);
    const {frameTree} = await cdpSession.send('Page.getFrameTree');
    console.log('Frame tree:', JSON.stringify(frameTree, null, 2).substring(0, 1000));
  }

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
