const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 返回到客户列表页，打开客户详情
  // 之前我们发现点击客户行会调用 customerV2Read/detail 和 customerRead/trailList
  // 现在让我找更多：看客户详情页面中的沟通相关 Tab

  // 先去客户详情页
  const customers = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json').customers;

  // 找一个有跟进记录的客户
  const withTrail = customers.find(c => c.last_trail_id > 0 && (c.trail_status_info?.info_label || '').includes('活跃'));
  const targetName = withTrail ? withTrail.name : customers[4].name;
  const targetId = withTrail ? withTrail.company_id : customers[4].company_id;
  console.log('Target customer:', targetName, 'ID:', targetId);

  // 设置全面的 API 监控
  const apiCalls = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (!url.includes('xiaoman.cn/api')) return;
    try {
      const ct = resp.headers()['content-type'] || '';
      if (!ct.includes('json')) return;
      const body = await resp.json();
      apiCalls.push({
        url: url.split('?')[0],
        status: resp.status(),
        dataKeys: Object.keys(body.data || {}).slice(0, 10),
        listLen: body.data?.list?.length || body.data?.records?.length,
      });
    } catch(e) {}
  });

  // 搜索这个客户并打开
  console.log('Searching for customer...');
  await page.goto('https://crm.xiaoman.cn/crm/customer/list', { waitUntil: 'domcontentloaded', timeout: 30000 });
  await page.waitForTimeout(2000);

  // 用搜索框搜客户
  const searchFilled = await page.evaluate((name) => {
    const inputs = document.querySelectorAll('input[placeholder*=搜索], input[class*=search], input[type=text]');
    for (const inp of inputs) {
      if (inp.offsetParent !== null) { // visible
        inp.value = name;
        inp.dispatchEvent(new Event('input', { bubbles: true }));
        return true;
      }
    }
    return false;
  }, targetName);
  console.log('Search filled:', searchFilled);

  if (searchFilled) {
    await page.keyboard.press('Enter');
    await page.waitForTimeout(3000);
  }

  // 点击客户行打开详情
  await page.evaluate((name) => {
    const rows = document.querySelectorAll('.row-item:not(.row-item__title)');
    for (const row of rows) {
      if (row.textContent.includes(name)) {
        row.click();
        return true;
      }
    }
    return false;
  }, targetName);
  await page.waitForTimeout(5000);

  console.log('');
  console.log('APIs called (' + apiCalls.length + '):');
  const chatApis = apiCalls.filter(a => a.url.includes('chat') || a.url.includes('message') || a.url.includes('talk'));
  const trailApis = apiCalls.filter(a => a.url.includes('trail'));

  // 过滤重复
  const seen = new Set();
  const unique = apiCalls.filter(a => {
    const key = a.url + a.listLen + a.dataKeys.join(',');
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });

  unique.forEach(a => {
    const label = chatApis.includes(a) ? '[CHAT]' : trailApis.includes(a) ? '[TRAIL]' : '';
    console.log(label + ' ' + a.status + ' ' + a.url + ' | list=' + a.listLen + ' | keys=' + a.dataKeys.join(','));
  });

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
