const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 直接调 API
  // 1. 找一个有 last_trail_id 的客户
  const customers = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json').customers;
  const target = customers.find(c => c.last_trail_id > 0 && c.name === 'Akbar Rahimi');
  const companyId = target ? target.company_id : 94260054430870;
  console.log('Testing with company_id:', companyId);

  // === Trail List API ===
  console.log('');
  console.log('=== 1. customerRead/trailList (跟进记录) ===');
  const trailList = await page.evaluate(async (cid) => {
    const xhr = new XMLHttpRequest();
    return new Promise((resolve) => {
      xhr.open('POST', 'https://crm.xiaoman.cn/api/customerRead/trailList', true);
      xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
      xhr.withCredentials = true;
      xhr.onload = () => resolve(JSON.parse(xhr.responseText));
      xhr.send('objCompanyId=' + cid + '&page=1&pageSize=20');
    });
  }, companyId);
  console.log('Keys:', Object.keys(trailList.data || {}));
  console.log('Total:', trailList.data?.totalItem);
  console.log('Tab list:', JSON.stringify(trailList.data?.tab_list));
  const trails = trailList.data?.list || [];
  console.log('Trail count:', trails.length);
  if (trails.length > 0) {
    console.log('');
    console.log('First trail sample:');
    const t = trails[0];
    for (const [k,v] of Object.entries(t)) {
      const val = typeof v === 'object' ? JSON.stringify(v).substring(0, 200) : v;
      console.log('  ' + k + ': ' + val);
    }
    // 看所有 trail 的类型
    const types = trails.map(t => t.trail_type_name || t.type_name || 'unknown');
    console.log('Trail types:', [...new Set(types)]);
  }

  // === Customer Detail API ===
  console.log('');
  console.log('=== 2. customerV2Read/detail (客户详情) ===');
  const detail = await page.evaluate(async (cid) => {
    const xhr = new XMLHttpRequest();
    return new Promise((resolve) => {
      xhr.open('POST', 'https://crm.xiaoman.cn/api/customerV2Read/detail', true);
      xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
      xhr.withCredentials = true;
      xhr.onload = () => resolve(JSON.parse(xhr.responseText));
      xhr.send('objCompanyId=' + cid);
    });
  }, companyId);
  console.log('Keys:', Object.keys(detail.data || {}));
  const values = detail.data?.values || {};
  // 只看有用的字段
  for (const [k,v] of Object.entries(values)) {
    if (v && typeof v === 'object' && v.info_label) {
      console.log('  ' + k + ': ' + v.info_label);
    }
  }

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
