const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));

  // 回到列表页
  await page.goto('https://crm.xiaoman.cn/crm/customer/list', { waitUntil: 'domcontentloaded', timeout: 30000 });
  await page.waitForTimeout(3000);

  // 拦截 REQUEST (不是 response) 以获取 POST body
  const requests = [];
  page.on('request', req => {
    const url = req.url();
    if (url.includes('trailList') || url.includes('customerV2Read/detail') || url.includes('customerRead/getReference')) {
      requests.push({
        url: url.split('?')[0],
        method: req.method(),
        postData: req.postData(),
        headers: req.headers(),
      });
    }
  });

  // 也拦截 response
  const responses = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (url.includes('trailList') || url.includes('customerV2Read/detail')) {
      try {
        const body = await resp.json();
        responses.push({
          url: url.split('?')[0],
          status: resp.status(),
          dataKeys: Object.keys(body.data || {}),
          listLen: body.data?.list?.length,
          total: body.data?.totalItem,
        });
      } catch(e) {}
    }
  });

  // 点击第一个数据行
  console.log('Clicking first data row...');
  const rows = await page.evaluate(() => {
    const rows = document.querySelectorAll('.row-item:not(.row-item__title)');
    if (rows.length > 0) {
      rows[0].click();
      return rows.length;
    }
    return 0;
  });
  console.log('Available rows:', rows);
  await page.waitForTimeout(5000);

  console.log('');
  console.log('=== REQUEST details ===');
  requests.forEach(r => {
    console.log('POST ' + r.url);
    console.log('  Body: ' + (r.postData || '(empty)'));
    console.log('  Content-Type: ' + (r.headers ? r.headers['content-type'] : 'unknown'));
  });

  console.log('');
  console.log('=== RESPONSE details ===');
  responses.forEach(r => {
    console.log(r.status + ' ' + r.url);
    console.log('  Keys: ' + r.dataKeys.join(', '));
    console.log('  List: ' + r.listLen + ' Total: ' + r.total);
  });

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
