      title: document.title,
      bodyClasses: document.body.className,
      rootDivs: document.querySelectorAll('body > div').length,
      allText: document.body.innerText?.substring(0, 2000),
    };

    return result;
  });

  console.log('Page title:', chatList.pageInfo.title);
  console.log('Body root divs:', chatList.pageInfo.rootDivs);
  console.log('');
  console.log('Contacts found:', chatList.contacts.length);
  chatList.contacts.slice(0, 30).forEach(c => {
    console.log('  [' + c.index + '] ' + (c.hasPin ? '📌' : '  ') + ' ' + c.text.substring(0, 100));
  });
  console.log('');
  console.log('=== Page body text (first 2000 chars) ===');
  console.log(chatList.pageInfo.allText);

  process.exit(0);
})().catch(e => { console.error(e.message); process.exit(1); });
