const http = require('http');

// 获取所有 CDP targets
const targets = await new Promise((resolve, reject) => {
  http.get('http://localhost:9222/json', (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => resolve(JSON.parse(data)));
  }).on('error', reject);
});

const tmTarget = targets.find(t => t.url.includes('onetalk.alibaba.com'));
console.log('TM Target:');
console.log('  id:', tmTarget?.id);
console.log('  url:', tmTarget?.url?.substring(0, 200));
console.log('  webSocketDebuggerUrl:', tmTarget?.webSocketDebuggerUrl?.substring(0, 100));

// 连接到 iframe target 并启用 Network
if (tmTarget) {
  const WebSocket = require('ws');
  const ws = new WebSocket(tmTarget.webSocketDebuggerUrl);

  await new Promise((resolve) => ws.on('open', resolve));

  // Enable Network
  ws.send(JSON.stringify({ id: 1, method: 'Network.enable' }));

  // 收集网络请求
  const requests = [];
  ws.on('message', (data) => {
    const msg = JSON.parse(data.toString());
    if (msg.method === 'Network.responseReceived') {
      const url = msg.params.response.url;
      if (url.includes('alibaba') && !url.includes('.js') && !url.includes('.css') && !url.includes('.png')) {
        requests.push({
          url: url.split('?')[0],
          status: msg.params.response.status,
          mimeType: msg.params.response.mimeType,
          requestId: msg.params.requestId,
        });
      }
    }
  });

  console.log('');
  console.log('Network monitoring active. Waiting 10s for traffic...');
  console.log('(请在 Chrome TM 页面点击一个聊天联系人)');

  await new Promise(r => setTimeout(r, 15000));

  // 尝试获取几个 JSON 响应的内容
  const jsonRequests = requests.filter(r => r.mimeType === 'application/json');
  console.log('');
  console.log('JSON requests captured (' + jsonRequests.length + '):');

  for (const req of jsonRequests.slice(0, 10)) {
    ws.send(JSON.stringify({ id: req.requestId, method: 'Network.getResponseBody', params: { requestId: req.requestId } }));
  }

  // 等响应
  await new Promise(r => setTimeout(r, 3000));

  ws.close();
  console.log('');
  console.log('Done. Total requests captured: ' + requests.length);
} else {
  console.log('TM target not found');
}

process.exit(0);
