/**
 * 探索 TM iframe 的网络请求 — 直接连 iframe 的 CDP target
 * 运行后请在 Chrome TM 页面点击一个聊天联系人
 */
const WebSocket = require('ws');
const http = require('http');

(async () => {
  // 获取所有 CDP targets
  const targets = await new Promise((resolve, reject) => {
    http.get('http://localhost:9222/json', (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve(JSON.parse(data)));
    }).on('error', reject);
  });

  const tmTarget = targets.find(t => t.url.includes('onetalk.alibaba.com'));
  if (!tmTarget) {
    console.log('TM target not found in:', targets.map(t => t.url.substring(0, 80)));
    process.exit(1);
  }

  console.log('TM Target found:', tmTarget.url.substring(0, 200));

  const ws = new WebSocket(tmTarget.webSocketDebuggerUrl);
  await new Promise((resolve) => ws.on('open', resolve));

  // Enable Network
  ws.send(JSON.stringify({ id: 1, method: 'Network.enable' }));
  await new Promise(r => setTimeout(r, 1000));

  const requests = [];
  const bodies = [];

  ws.on('message', (data) => {
    const msg = JSON.parse(data.toString());

    if (msg.method === 'Network.responseReceived') {
      const resp = msg.params.response;
      const url = resp.url;
      if (url.includes('mtop') || url.includes('message') || url.includes('chat') || url.includes('contact') || url.includes('session')) {
        requests.push({ url, requestId: msg.params.requestId, mimeType: resp.mimeType });
      }
    }

    if (msg.id && msg.result?.body) {
      bodies.push({ id: msg.id, body: msg.result.body.substring(0, 500), base64: msg.result.base64Encoded });
    }
  });

  console.log('Monitoring network... (15 seconds)');
  console.log('Click a chat contact in Chrome TM page NOW');
  await new Promise(r => setTimeout(r, 15000));

  // 获取 JSON 响应的 body
  for (const req of requests.filter(r => r.mimeType === 'application/json').slice(0, 10)) {
    ws.send(JSON.stringify({
      id: bodies.length + 1,
      method: 'Network.getResponseBody',
      params: { requestId: req.requestId }
    }));
  }
  await new Promise(r => setTimeout(r, 3000));

  console.log('');
  console.log('=== Captured requests (' + requests.length + ') ===');
  requests.forEach(r => console.log('  ' + r.mimeType + ' ' + r.url.substring(0, 150)));

  console.log('');
  console.log('=== Response bodies (' + bodies.length + ') ===');
  bodies.forEach(b => console.log('  [' + b.id + '] base64=' + b.base64 + ' ' + b.body.substring(0, 300)));

  ws.close();
  console.log('Done.');
  process.exit(0);
})().catch(err => { console.error(err.message); process.exit(1); });

