const data = require('d:/ClaudeWorkspace/08_客户跟进/Okki/data/okki_full_2026-05-05T05-17-48.json');
const c = data.customers[0];

// 分类：核心 vs 无用
const essential = ['name','company_id','country','performance_order_count','transaction_order_amount','archive_time','order_time','alibaba_relation_list'];
const useless = ['serial_id','cus_tag_info','trail_status_info','origin_list_info','score','customer_count','contact_count','serial_id_info','cus_tag','client_tag_list','group_id','pool_id','public_reason_id','business_type_id','duplicate_flag','pin_flag','opportunity_flag','ai_qc_flag','layout_rules','operate_privilege','main_customer','main_lead_id','relate_lead_ids','relate_lead_info'];
const redundant = ['_info']; // 所有 _info 后缀

// 计算大小
let essentialBytes = 0, uselessBytes = 0, redundantBytes = 0, otherBytes = 0;
for (const [k,v] of Object.entries(c)) {
  const size = JSON.stringify(v).length;
  const isInfo = k.endsWith('_info');
  if (essential.includes(k)) essentialBytes += size;
  else if (useless.includes(k)) uselessBytes += size;
  else if (isInfo) redundantBytes += size;
  else otherBytes += size;
}

const total = essentialBytes + uselessBytes + redundantBytes + otherBytes;
console.log('单客户原始 JSON 大小分布:');
console.log('  核心字段: ' + (essentialBytes/1024).toFixed(2) + ' KB (' + (essentialBytes/total*100).toFixed(0) + '%)');
console.log('  冗余_info: ' + (redundantBytes/1024).toFixed(2) + ' KB (' + (redundantBytes/total*100).toFixed(0) + '%)');
console.log('  无用字段: ' + (uselessBytes/1024).toFixed(2) + ' KB (' + (uselessBytes/total*100).toFixed(0) + '%)');
console.log('  其他:     ' + (otherBytes/1024).toFixed(2) + ' KB (' + (otherBytes/total*100).toFixed(0) + '%)');
console.log('  总计:     ' + (total/1024).toFixed(2) + ' KB');

// 算算 346 人
const total346 = total * 346;
console.log('');
console.log('346 人全量: ' + (total346/1024).toFixed(0) + ' KB = ' + (total346/1024/1024).toFixed(1) + ' MB');
console.log('精简后:     ' + ((essentialBytes+otherBytes)*346/1024).toFixed(0) + ' KB = ' + ((essentialBytes+otherBytes)*346/1024/1024).toFixed(1) + ' MB');
console.log('可砍掉:     ' + ((uselessBytes+redundantBytes)*346/1024).toFixed(0) + ' KB = ' + ((uselessBytes+redundantBytes)*346/1024/1024).toFixed(1) + ' MB');

// 抓取时间影响
const fieldsCount = Object.keys(c).length;
const uselessCount = useless.length + Object.keys(c).filter(k => k.endsWith('_info') && !essential.includes(k)).length;
console.log('');
console.log('字段数: ' + fieldsCount + ' 个, 可砍 ' + uselessCount + ' 个');
console.log('API 返回数据量影响: 砍掉字段在 API 响应中依然存在（服务端返回全量），对抓取速度几乎无影响');
console.log('落盘写入影响: 减少 ' + ((uselessBytes+redundantBytes)/total*100).toFixed(0) + '% I/O，几乎没有可感知差异');
